#include<bits/stdc++.h>
using namespace std;
long long gcd(long long x,long long y)
{
    return(x%y==0?y:gcd(y,x%y));
}
void yuefen(long long &x,long long &y)
{
    long long g=gcd(x,y);
    x/=g;
    y/=g;
}
void dfs(long long a,long long b,long long c,long long d,long long &x,long long &y)
{
    if(a<b&&c>d)
    {
        x=1;
        y=1;
    }
    else
    {
        dfs(d%c,c,b-(d/c)*a,a,y,x);
        y+=(d/c)*x;
    }
}
int main()
{
    // int t;
    // scanf("%d",&t);
    // while(t--)
    long long a,b,c,d;
    while(scanf("%lld%lld%lld%lld",&a,&b,&c,&d)==4)
    {
        // scanf("%lld%lld%lld%lld",&a,&b,&c,&d);
        long long p,q;
        dfs(a,b,c,d,p,q);
        yuefen(p,q);
        printf("%lld/%lld\n",p,q);
    }
    return 0;
}
